// ── COMPOSANT PRINCIPAL ───────────────────────────────────────────────────────

type LabRequisitionPDFProps = {
  fullName: string
  email: string
  age: number
  sex: string
  memberTier: 'premium' | 'executive'
  locale: string
  date: string
}

export default function LabRequisitionPDF({
  fullName,
  email,
  age,
  sex,
  memberTier,
  locale,
  date,
}: LabRequisitionPDFProps) {

  const isExecutive = memberTier === 'executive'
  const panels = isExecutive
    ? [...PREMIUM_PANELS, ...EXECUTIVE_ONLY_PANELS]
    : PREMIUM_PANELS

  const totalMarkers = panels.reduce((acc, p) => acc + p.markers.length, 0)

  const titles: Record<string, Record<string, string>> = {
    en: {
      docTitle: 'Laboratory Requisition — Longevity Biomarker Panel',
      patient: 'Patient',
      dob: 'Age',
      sex: 'Sex',
      tier: memberTier === 'executive' ? 'Executive Plan' : 'Premium Plan',
      dateLabel: 'Date',
      intro: 'Please present this document to your healthcare provider or laboratory. Request each test listed below. Results should be fasted (minimum 10-12 hours) for metabolic markers.',
      test: 'Test Name',
      unit: 'Unit',
      reference: 'Optimal Range',
      result: 'Result',
      disclaimer: 'MEDICAL DISCLAIMER: This requisition is for wellness and longevity optimization purposes only. It does not constitute a medical diagnosis, treatment plan, or clinical prescription. Please consult your healthcare provider before undertaking any laboratory tests.',
      footer: 'Lonara Labs — app.lonaralabs.com — Confidential',
    },
    fr: {
      docTitle: 'Réquisition de Laboratoire — Panel de Biomarqueurs de Longévité',
      patient: 'Patient',
      dob: 'Âge',
      sex: 'Sexe',
      tier: memberTier === 'executive' ? 'Plan Executive' : 'Plan Premium',
      dateLabel: 'Date',
      intro: 'Veuillez présenter ce document à votre médecin ou laboratoire. Demandez chaque analyse listée ci-dessous. Les prises de sang métaboliques doivent être effectuées à jeun (minimum 10-12 heures).',
      test: 'Nom du Test',
      unit: 'Unité',
      reference: 'Plage Optimale',
      result: 'Résultat',
      disclaimer: 'AVERTISSEMENT MÉDICAL : Cette réquisition est destinée uniquement à des fins de bien-être et d\'optimisation de la longévité. Elle ne constitue pas un diagnostic médical, un plan de traitement ou une ordonnance clinique. Veuillez consulter votre médecin avant d\'effectuer des analyses de laboratoire.',
      footer: 'Lonara Labs — app.lonaralabs.com — Confidentiel',
    },
    es: {
      docTitle: 'Requisición de Laboratorio — Panel de Biomarcadores de Longevidad',
      patient: 'Paciente',
      dob: 'Edad',
      sex: 'Sexo',
      tier: memberTier === 'executive' ? 'Plan Executive' : 'Plan Premium',
      dateLabel: 'Fecha',
      intro: 'Presente este documento a su médico o laboratorio. Solicite cada análisis listado a continuación. Los análisis metabólicos deben realizarse en ayunas (mínimo 10-12 horas).',
      test: 'Nombre del Análisis',
      unit: 'Unidad',
      reference: 'Rango Óptimo',
      result: 'Resultado',
      disclaimer: 'AVISO MÉDICO: Esta requisición es solo para fines de bienestar y optimización de la longevidad. No constituye un diagnóstico médico, plan de tratamiento o receta clínica. Consulte a su médico antes de realizarse análisis de laboratorio.',
      footer: 'Lonara Labs — app.lonaralabs.com — Confidencial',
    },
  }

  const t = titles[locale] ?? titles.en

  const getPanelName = (panel: typeof PREMIUM_PANELS[0]) => {
    if (locale === 'fr') return panel.panelFR
    if (locale === 'es') return panel.panelES
    return panel.panel
  }

  return (
    <Document>
      <Page size="A4" style={styles.page} wrap>

        {/* HEADER */}
        <View style={styles.header}>
          <View>
            <Text style={styles.brandName}>LONARA LABS</Text>
            <Text style={styles.docTitle}>{t.docTitle}</Text>
            <Text style={styles.docDate}>{t.dateLabel}: {date}</Text>
          </View>
          <Image src={LOGO_BASE64} style={styles.logo} />
        </View>

        {/* PATIENT INFO */}
        <View style={styles.patientBox}>
          <View>
            <Text style={styles.patientLabel}>{t.patient}</Text>
            <Text style={styles.patientValue}>{fullName}</Text>
            <Text style={{ fontSize: 8, color: '#888', marginTop: 2 }}>{email}</Text>
          </View>
          <View>
            <Text style={styles.patientLabel}>{t.dob}</Text>
            <Text style={styles.patientValue}>{age} ans</Text>
          </View>
          <View>
            <Text style={styles.patientLabel}>{t.sex}</Text>
            <Text style={styles.patientValue}>{sex}</Text>
          </View>
          <View>
            <View style={styles.tierBadge}>
              <Text style={styles.tierText}>{t.tier}</Text>
            </View>
            <Text style={{ fontSize: 8, color: '#888', marginTop: 4 }}>
              {totalMarkers} {locale === 'fr' ? 'analyses' : locale === 'es' ? 'análisis' : 'tests'}
            </Text>
          </View>
        </View>

        {/* INTRO NOTE */}
        <Text style={styles.introText}>{t.intro}</Text>

        {/* PANELS */}
        {panels.map((panelGroup, pIndex) => (
          <View key={pIndex} style={styles.panelBlock} wrap={false}>

            {/* PANEL HEADER */}
            <View style={styles.panelHeader}>
              <Text style={styles.panelTitle}>{getPanelName(panelGroup)}</Text>
              <Text style={styles.panelCount}>{panelGroup.markers.length} tests</Text>
            </View>

            {/* COLUMN HEADERS */}
            <View style={styles.columnHeader}>
              <Text style={[styles.colLabel, { flex: 1 }]}>{t.test}</Text>
              <Text style={[styles.colLabel, { width: 60, textAlign: 'center' }]}>{t.unit}</Text>
              <Text style={[styles.colLabel, { width: 140, textAlign: 'right' }]}>{t.reference}</Text>
              <Text style={[styles.colLabel, { width: 80, textAlign: 'right' }]}>{t.result}</Text>
            </View>

            {/* MARKERS */}
            {panelGroup.markers.map((marker, mIndex) => (
              <View
                key={mIndex}
                style={[styles.markerRow, mIndex % 2 === 1 ? styles.markerRowAlt : {}]}
              >
                <View style={styles.checkbox} />
                <Text style={styles.markerName}>{marker.name}</Text>
                <Text style={styles.markerUnit}>{marker.unit}</Text>
                <Text style={styles.markerRef}>{marker.ref}</Text>
                <Text style={styles.markerValue}>____________</Text>
              </View>
            ))}

          </View>
        ))}

        {/* DISCLAIMER */}
        <View style={styles.disclaimer}>
          <Text style={styles.disclaimerText}>{t.disclaimer}</Text>
        </View>

        {/* FOOTER */}
        <View style={styles.footer} fixed>
          <Text style={styles.footerText}>{t.footer}</Text>
          <Text style={styles.footerText}>{fullName} — {date}</Text>
        </View>

        {/* PAGE NUMBER */}
        <Text
          fixed
          style={styles.pageNumber}
          render={({ pageNumber, totalPages }) => `${pageNumber} / ${totalPages}`}
        />

      </Page>
    </Document>
  )
}
